INSERT OR REPLACE INTO reports (id, status, election, title, summary, body, sido, sigungu, eup_myeon_dong, occurred_at, collected_at, tags, sources, attachments, exif, rebuttals, related, consent, submitter, license, verification_reviewer, verification_method, verification_reviewed_at, verification_notes, verification_evidence_links, verification_status_scope, verification_claim, verification_verified_facts, verification_assessment, verification_confirmed_scope, verification_not_confirmed, verification_possible_explanations, verification_missing_evidence, verification_reviewer_note, verification_public_summary, verification_risk_level, finalize_token, staging, created_at, updated_at) VALUES ('cd2429c37672', 'debunked', '제9회 전국동시지방선거', '투표함 이동을 불법으로 본 주장', NULL, NULL, '서울특별시', NULL, NULL, NULL, '2026-06-09T21:01:00.000Z', '["투표·개표 과정"]', '[{"url":"https://example.com/votatis-data/4","type":"submitter"}]', '[]', NULL, NULL, NULL, 1, 'seed:votatis-data', 'CC-BY-4.0', '검증자(예시)', '공직선거법·중앙선관위 절차 대조', '2026-06-10T02:00:00.000Z', NULL, '["https://law.go.kr/공직선거법"]', NULL, '선거기간 중 개인이 투표함을 이동시킨 것은 불법이라는 주장', '["영상에서 투표함을 이동하는 장면이 확인된다"]', NULL, NULL, '["해당 이동이 불법이라는 주장","부정선거 조작이 있었다는 주장"]', '["정당한 권한자(선거사무원)에 의한 규정상 이송일 가능성"]', NULL, NULL, '영상상 투표함 이동 정황은 확인되나, 권한 없는 자의 불법 이동이라는 핵심 전제는 절차·법령과 충돌한다. 정당한 이송일 가능성이 크다.', '낮음~중간', NULL, NULL, '2026-06-09T21:01:00.000Z', '2026-06-09T21:01:00.000Z');
INSERT OR REPLACE INTO reports (id, status, election, title, summary, body, sido, sigungu, eup_myeon_dong, occurred_at, collected_at, tags, sources, attachments, exif, rebuttals, related, consent, submitter, license, verification_reviewer, verification_method, verification_reviewed_at, verification_notes, verification_evidence_links, verification_status_scope, verification_claim, verification_verified_facts, verification_assessment, verification_confirmed_scope, verification_not_confirmed, verification_possible_explanations, verification_missing_evidence, verification_reviewer_note, verification_public_summary, verification_risk_level, finalize_token, staging, created_at, updated_at) VALUES ('800732950781', 'disputed', '제9회 전국동시지방선거', '봉인지에 투표관리관 서명이 없는 투표함을 개표소에 반입', NULL, NULL, '경기도', NULL, NULL, NULL, '2026-06-09T21:02:00.000Z', '["투표·개표 과정"]', '[{"url":"https://example.com/votatis-data/5","type":"submitter"}]', '[]', NULL, NULL, NULL, 1, 'seed:votatis-data', 'CC-BY-4.0', '검증자(예시)', '사진 판독 + 개표 절차 확인', '2026-06-10T02:00:00.000Z', NULL, '["https://example.com/evidence/5"]', NULL, '봉인지에 투표관리관 서명이 없는 투표함이 개표소에 반입되었다는 주장', '["사진상 봉인지의 서명란 식별이 어렵다"]', NULL, NULL, '["서명 누락이 확정적이라는 주장","부정선거 조작이 있었다는 주장"]', '["촬영 각도·해상도로 서명이 보이지 않았을 가능성"]', NULL, NULL, '사진만으로는 서명 유무를 단정하기 어렵다. 원본 고해상 자료와 개표록 확인이 필요하다.', '낮음~중간', NULL, NULL, '2026-06-09T21:02:00.000Z', '2026-06-09T21:02:00.000Z');
INSERT OR REPLACE INTO reports (id, status, election, title, summary, body, sido, sigungu, eup_myeon_dong, occurred_at, collected_at, tags, sources, attachments, exif, rebuttals, related, consent, submitter, license, verification_reviewer, verification_method, verification_reviewed_at, verification_notes, verification_evidence_links, verification_status_scope, verification_claim, verification_verified_facts, verification_assessment, verification_confirmed_scope, verification_not_confirmed, verification_possible_explanations, verification_missing_evidence, verification_reviewer_note, verification_public_summary, verification_risk_level, finalize_token, staging, created_at, updated_at) VALUES ('59547c149c47', 'confirmed', '제9회 전국동시지방선거', '선관위 투표진행상황 화면 누적 투표자수 감소 표출 오류', NULL, NULL, '전국', NULL, NULL, NULL, '2026-06-09T21:03:00.000Z', '["전산·통계 이상"]', '[{"url":"https://example.com/votatis-data/6","type":"submitter"}]', '[]', NULL, NULL, NULL, 1, 'seed:votatis-data', 'CC-BY-4.0', '검증자(예시)', '두 시점 캡처 수치 대조', '2026-06-10T02:00:00.000Z', NULL, '["https://example.com/evidence/6a","https://example.com/evidence/6b"]', '선관위 투표진행상황 화면상 누적 투표자수 감소 및 시스템 표출 정합성 미흡', '30초 사이 화면상 누적 투표자수가 110명 감소했다는 주장', '["17:05:30 표시값 25,617,541명","17:06:00 표시값 25,617,431명","두 값의 차이는 -110명"]', NULL, '["화면상 누적 투표자수 110명 감소","투표진행상황 시스템의 표출 정합성 미흡"]', '["실제 물리적 투표자수 감소","임의조정·리밸런싱 주장","부정선거 조작이 있었다는 주장","개표 결과에 영향을 주었다는 주장"]', '["서로 다른 CDN/캐시 노드의 값 불일치","캐시 무효화 미흡"]', NULL, NULL, '화면상 누적 투표자수가 30초 사이 110명 감소한 정황이 확인된다. 이는 시스템 표출 정합성 관리 미흡 사례로 볼 수 있다. 다만 실제 투표자수 감소·임의조정·부정선거를 입증하는 것은 아니다.', '중간', NULL, NULL, '2026-06-09T21:03:00.000Z', '2026-06-09T21:03:00.000Z');
