INSERT OR REPLACE INTO reports (id, status, election, title, summary, body, sido, sigungu, eup_myeon_dong, occurred_at, collected_at, tags, sources, attachments, exif, rebuttals, related, consent, submitter, license, verification_reviewer, verification_method, verification_reviewed_at, verification_notes, verification_evidence_links, verification_status_scope, verification_claim, verification_verified_facts, verification_assessment, verification_confirmed_scope, verification_not_confirmed, verification_possible_explanations, verification_missing_evidence, verification_reviewer_note, verification_public_summary, verification_risk_level, finalize_token, staging, created_at, updated_at) VALUES ('d39c7ae53251', 'confirmed', '제9회 전국동시지방선거', '구로3동 제6투표소 투표함 봉인지 2겹 부착에 따른 봉인 관리 미흡', NULL, NULL, '서울특별시', '구로구', NULL, NULL, '2026-06-09T21:05:00.000Z', '["투표·개표 과정"]', '[{"url":"https://example.com/votatis-data/8","type":"submitter"}]', '[]', NULL, NULL, NULL, 1, 'seed:votatis-data', 'CC-BY-4.0', '검증자(예시)', '사진 판독 + 봉인 절차 확인', '2026-06-10T02:00:00.000Z', NULL, '["https://example.com/evidence/8"]', '투표함 봉인지 2겹 부착에 따른 봉인 관리 미흡', '구로3동 제6투표소 투표함이 봉인지 2겹이 붙은 채 반입되어 개함이 보류되었다는 주장', '["사진상 특수봉인지가 2겹으로 겹쳐 붙어 있는 것으로 보인다","상단 라벨에서 ''구로3동 제6투표소'' 표기가 확인된다"]', NULL, '["봉인지 2겹 부착 정황","봉인 상태 외관 이상","봉인 관리 미흡"]', '["투표함이 실제 개봉되었다는 주장","투표지가 훼손되었다는 주장","봉인지 불법 교체 주장","부정선거 조작이 있었다는 주장"]', '["기존 봉인지 들뜸 방지용 덧봉인 가능성","현장 보완 조치 후 기록·설명 미흡"]', NULL, NULL, '봉인지가 2겹으로 부착된 정황이 확인된다. 정상적인 봉인 관리로 보기 어려워 최소한 봉인 관리·설명 책임 미흡 사례로 볼 수 있다. 다만 개봉·훼손·불법 교체·부정선거를 단정할 수는 없다.', '중간~높음', NULL, NULL, '2026-06-09T21:05:00.000Z', '2026-06-09T21:05:00.000Z');
