INSERT OR REPLACE INTO reports (id, status, election, title, summary, body, sido, sigungu, eup_myeon_dong, occurred_at, collected_at, tags, sources, attachments, exif, rebuttals, related, consent, submitter, license, verification_reviewer, verification_method, verification_reviewed_at, verification_notes, verification_evidence_links, verification_status_scope, verification_claim, verification_verified_facts, verification_assessment, verification_confirmed_scope, verification_not_confirmed, verification_possible_explanations, verification_missing_evidence, verification_reviewer_note, verification_public_summary, verification_risk_level, finalize_token, staging, created_at, updated_at) VALUES ('46a18d3321b9', 'confirmed', '제9회 전국동시지방선거', '용인 개표소 투표지분류기 후보별 연속 분류 패턴 확인', NULL, NULL, '경기도', '용인시', NULL, NULL, '2026-06-09T21:07:15.112Z', '["전산·통계 이상"]', '[{"url":"https://www.youtube.com/watch?v=TUa4LBBkzB8","type":"submitter"}]', '[]', NULL, NULL, NULL, 1, 'seed:votatis-data', 'CC-BY-4.0', '검증자(예시)', '영상 구간 분석', '2026-06-10T02:00:00.000Z', NULL, '["https://www.youtube.com/watch?v=TUa4LBBkzB8"]', '영상상 투표지분류기 후보별 연속 분류 패턴(추가 분석 필요)', '3분간 1번, 1분간 2번 등 이상 패턴으로 개표가 진행됐다는 주장', '["영상상 특정 구간에서 후보별 연속 분류 패턴이 관찰된다"]', NULL, '["영상상 연속 분류 패턴"]', '["장비 조작이 있었다는 주장","부정선거 조작이 있었다는 주장","개표 결과에 영향을 주었다는 주장"]', '["투표지가 충분히 섞이지 않아 묶음 단위 편중","소분 묶음 연속 투입"]', NULL, NULL, '영상에서 후보별 연속 분류 패턴이 관찰된다. 다만 이는 투표지 미혼합·묶음 편중 등으로도 설명 가능하며, 장비 조작이나 부정선거를 입증하지 않는다. 추가 분석이 필요하다.', '중간', NULL, NULL, '2026-06-09T21:07:15.112Z', '2026-06-09T21:07:15.112Z');
